import { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import api from "../services/api";
import PostItem from "../components/PostItem";
import MapView from "../components/MapView";
import toast from "react-hot-toast";

export default function Dashboard() {

  const [items, setItems] = useState([]);
  const [nearbyItems, setNearbyItems] = useState([]);
  const [filter, setFilter] = useState("");
  const [loading, setLoading] = useState(true);

  const user = JSON.parse(localStorage.getItem("user") || "null");
  const userId = user?._id || null;

  const loadItems = async () => {

    try {

      setLoading(true);

      const res = await api.get("/items");

      setItems(res.data);

    } catch {

      toast.error("Failed to load items");

    } finally {

      setLoading(false);

    }

  };

  useEffect(() => {
    loadItems();
  }, []);

  /* FIND NEARBY ITEMS */

  const findNearbyItems = () => {

    if (!navigator.geolocation) {
      toast.error("Geolocation not supported");
      return;
    }

    navigator.geolocation.getCurrentPosition(async (position) => {

      const lat = position.coords.latitude;
      const lng = position.coords.longitude;

      try {

        const res = await api.get(`/items/nearby?lat=${lat}&lng=${lng}`);

        setNearbyItems(res.data);

        toast.success("Nearby items loaded");

      } catch {

        toast.error("Failed to load nearby items");

      }

    });

  };

  const filteredItems = filter
    ? items.filter((i) => i.type === filter)
    : items;

  const lostCount = items.filter((i) => i.type === "lost").length;
  const foundCount = items.filter((i) => i.type === "found").length;

  const getImageUrl = (path) => {
    if (!path) return null;
    if (path.startsWith("http")) return path;
    return `http://localhost:5000${path.startsWith("/") ? "" : "/"}${path}`;
  };

  if (loading) {

    return (

      <div className="p-8 text-center text-lg">
        Loading dashboard...
      </div>

    );

  }

  return (

    <div className="min-h-screen bg-gradient-to-br from-gray-50 to-blue-50 p-6">

      {/* HEADER */}

      <div className="bg-white rounded-xl shadow p-6 mb-8">

        <h1 className="text-3xl font-extrabold">
          weFOUNDit
        </h1>

        <p className="text-gray-600 mt-2">
          Community powered Lost & Found system
        </p>

      </div>

      {/* STATS */}

      <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-8">

        <StatCard title="Total Items" value={items.length} />
        <StatCard title="Lost Items" value={lostCount} color="red" />
        <StatCard title="Found Items" value={foundCount} color="green" />

      </div>

      {/* NEARBY BUTTON */}

      <button
        onClick={findNearbyItems}
        className="mb-8 bg-purple-600 text-white px-4 py-2 rounded"
      >
        Find Nearby Items
      </button>

      {/* NEARBY RESULTS */}

      {nearbyItems.length > 0 && (

        <div className="mb-10">

          <h2 className="text-xl font-bold mb-4">
            Nearby Items
          </h2>

          <div className="grid md:grid-cols-3 gap-4">

            {nearbyItems.map(item => (

              <div key={item._id} className="bg-white p-4 rounded shadow">

                <h3 className="font-bold">{item.title}</h3>

                <p className="text-sm text-gray-500">
                  {item.description}
                </p>

                <Link
                  to={`/items/${item._id}`}
                  className="text-blue-600 text-sm"
                >
                  View Item
                </Link>

              </div>

            ))}

          </div>

        </div>

      )}

      {/* MAP */}

      <div className="bg-white rounded-xl shadow p-6 mb-10">

        <h2 className="text-2xl font-bold mb-4">
          Lost & Found Map
        </h2>

        <MapView items={items} />

      </div>

      {/* POST ITEM */}

      <div className="mb-8">
        <PostItem onPosted={loadItems} />
      </div>

      {/* ITEMS */}

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">

        {filteredItems.map((item) => {

          const isOwner =
            userId &&
            (typeof item.user === "string"
              ? item.user
              : item.user?._id) === userId;

          const imageUrl =
            item.images?.length > 0
              ? getImageUrl(item.images[0])
              : null;

          return (

            <div
              key={item._id}
              className="bg-white rounded-xl shadow p-4"
            >

              {imageUrl && (

                <img
                  src={imageUrl}
                  alt={item.title}
                  className="h-40 w-full object-cover rounded-lg mb-3"
                />

              )}

              <h2 className="text-lg font-bold mb-1">
                {item.title}
              </h2>

              <p className="text-sm text-gray-600">
                {item.description}
              </p>

              <Link
                to={`/items/${item._id}`}
                className="block mt-3 text-center bg-blue-600 text-white py-2 rounded"
              >
                View Details
              </Link>

            </div>

          );

        })}

      </div>

    </div>

  );

}

function StatCard({ title, value, color = "blue" }) {

  const map = {
    blue: "text-blue-600 bg-blue-50",
    red: "text-red-600 bg-red-50",
    green: "text-green-600 bg-green-50"
  };

  return (

    <div className={`rounded-xl p-5 shadow ${map[color]}`}>

      <p className="text-sm font-medium">{title}</p>

      <p className="text-3xl font-extrabold mt-2">{value}</p>

    </div>

  );

}
